((SELECT id FROM kata WHERE kata='/'), 'alasan yg dapat dipakai untuk memperkuat atau menolak suatu pendapat, pendirian, atau gagasan: -- nya dapat diterima krn tidak bertentangan dng anggaran dasar perkumpulan'),
