((SELECT id FROM kata WHERE kata='/'), 'kumpulan barangbarang pilihan dr benda-benda yg bersesuaian atau berlain-lain (dl toko dsb)'),
((SELECT id FROM kata WHERE kata='/, mengaben'), 'membakar mayat (upacara kematian dl masyarakat Bali)'),
