((SELECT id FROM kata WHERE kata='A'), 'Ampere; lambang satuan ukuran arus listrik'),
((SELECT id FROM kata WHERE kata='Adam'), '1 nama manusia pertama yg dijadikan oleh Tuhan; 2 laki-laki'),
((SELECT id FROM kata WHERE kata='Agustus'), 'bulan kedelapan dl perhitungan tahun Masehi'),
((SELECT id FROM kata WHERE kata='Ahad'), '1 satu; esa; 2 hari yg pertama dl seminggu; 3 hari yg ditentukan sbg hari libur kerja bagi pegawai dan murid sekolah; Minggu'),
((SELECT id FROM kata WHERE kata='Aljalil'), 'Yang Mahamulia (Allah)'),
((SELECT id FROM kata WHERE kata='Alkabir'), 'Yang Mahabesar (Allah)'),
((SELECT id FROM kata WHERE kata='Alkadir'), 'Yang Mahakuasa (Allah)'),
((SELECT id FROM kata WHERE kata='Allah'), 'nama Tuhan dl bahasa Arab; Tuhan Yang MahaEsa yg disembah oleh orang yg beriman'),
((SELECT id FROM kata WHERE kata='Allahuakbar'), 'Allah Yang Mahabesar'),
((SELECT id FROM kata WHERE kata='Almasih'), '1 Isl yg diselamatkan; 2 yg diurapi: Isa --; 3 Yesus Kristus yg menyelamatkan umat manusia'),
((SELECT id FROM kata WHERE kata='Alquran'), 'firman-firman Allah yg diturunkan kpd Nabi Muhammad saw. dng perantara malaikat Jibril untuk dibaca, dipahami, dan diamalkan sbg petunjuk atau pedoman hidup bagi umat manusia; Kitab suci umat Islam'),
((SELECT id FROM kata WHERE kata='Anda'), 'sapaan untuk orang kedua dng tidak membedakan tingkat, kedudukan, dan umur; kamu; engkau: surat lamaran -- sudah kami terima'),
((SELECT id FROM kata WHERE kata='April'), 'bulan keempat tahun Masehi; bulan setelah bulan Maret dan sebelum bulan Mei'),
((SELECT id FROM kata WHERE kata='Arab'), 'nama bangsa dan bahasa di jazirah Arab dan Asia Tengah'),
((SELECT id FROM kata WHERE kata='Arbaa'), 'hari Rabu'),
((SELECT id FROM kata WHERE kata='Aries'), 'Astrol 1 rasi bintang dilangit belahan bumi utara dengan Taurus dan Pises; 2 lambang pertama zodiak; 3 lambang bagi orang-orang yg dilahirkan pd tanggal 21 Maret sampai 20 April (arti sebenarnya domba jantan)'),
((SELECT id FROM kata WHERE kata='Aru'), 'gelar bangsawan Bugis'),
((SELECT id FROM kata WHERE kata='_ pengatur'), 'gatur n orang (badan dsb) yg mengatur'),
((SELECT id FROM kata WHERE kata='a'), 'are; nama satuan ukuran luas (= 100 m )'),
((SELECT id FROM kata WHERE kata='ab'), 'tabung atau kotak candu terbuat dr tanah'),
((SELECT id FROM kata WHERE kata='aba'), 'ayah; bapak; (kadang-kadang juga berarti) kakek'),
((SELECT id FROM kata WHERE kata='aba-aba'), 'kata-kata perintah atau komando, spt dl baris-berbaris, senam, atau menyanyi bersama, msl siap!, kiri! kanan!, satu! dua!, maju jalan!'),
((SELECT id FROM kata WHERE kata='abad'), '1 masa seratus tahun: umurnya sudah setengah --; 2 jangka waktu yg lamanya seratus tahun: -- ke-20 dimulai dr tahun 1901 sampai tahun 2000; 3 zaman (yg lamanya tidak tentu); 4 kl masa yg kekal, tidak berkesudahan; -- kekal selama-lamanya; -- keemasan masa kegemilangan dan kejayaan yg dialami suatu bangsa atau negara dl sejarahnya; -- pertengahan zaman dl sejarah Eropa antara zaman purbakala dan zaman baru (tahun 476--1492); beratus-ratus tahun: ~ lamanya bangsa kita dijajah'),
((SELECT id FROM kata WHERE kata='abadi'), 'tetap ada sepanjang masa; tidak berkesudahan: hanya Tuhan saja yg --; semua orang mendambakan kedamaian yg --; 2 menjadikan peringatan yg kekal; membuat gambar kenang-kenangan (dng dipotret, dilukis, dsb): para wartawan foto dan te- levisi ~ upacara pembukaan Konferensi Asia-Afrika; 2 tempat yg abadi (alam baka): kenanglah pahlawan kita yg telah bersemayam di ~'),
((SELECT id FROM kata WHERE kata='abadiah'), 'kekekalan'),
((SELECT id FROM kata WHERE kata='abadiat'), 'lihat abadiah'),
((SELECT id FROM kata WHERE kata='abah'), 'arah; tuju: tidak tentu --nya; menujukan: mereka ~ kapalnya ke pulau itu'),
((SELECT id FROM kata WHERE kata='abah'), 'lihat aba'),
((SELECT id FROM kata WHERE kata='abah-abah'), '1 alat; perkakas; 2 tali-temali; -- kuda pakaian kuda (tali kang, pelana, dsb); --  perahu tali-- temali perahu; -- tenun perkakas tenun'),
((SELECT id FROM kata WHERE kata='abai'), '1 tidak dihiraukan (tidak dilakukan dng sungguh-sungguh; tidak diindahkan dsb); 2 lalai: anak-anak tidak boleh -- thd nasihat orang tua dan guru; jangan ~ kemampuan musuh; 2 tidak mengindahkan (perintah, nasihat): ~ perintah agama; 3 melalaikan (kewajiban, tugas, pekerjaan ); 4 menyianyiakan; tidak menggunakan baik-baik: ia tidak ~ peluang yg ada; 5 tidak memedulikan (kritik, celaan): mereka ~ kritik yg ditujukan kepadanya; 6 membiarkan telantar (terbengkalai dsb): ~ keluarganya; 7 tidak memegang teguh (adat istiadat, aturan, janji): negara itu ~ ketentuan-ketentuan yg telah disepakati dunia internasional'),
((SELECT id FROM kata WHERE kata='abaian'), 'Filol penghilangan atau pengubahan bagian naskah yg tidak dipahami lagi oleh penyalin; pelengah; terlalaikan; tidak dipedulikan; 2 dapat diabaikan: bagaimanapun jasa-jasanya tidak ~'),
((SELECT id FROM kata WHERE kata='abaimana'), '1 lubang pelepasan; dubur; 2 kemaluan'),
((SELECT id FROM kata WHERE kata='abakus'), 'alat untuk menghitung, yg berupa deretan bulatan dr kayu, plastik yg bertusuk, setiap tusuk berisi sepuluh buah'),
((SELECT id FROM kata WHERE kata='abakus'), 'Tek lempeng datar di atas kepala tiang dng pinggiran cekung atau beralur'),
((SELECT id FROM kata WHERE kata='abampere'), 'satuan arus elektrik dalam sistem sentimeter-gram-sekon (cgs) elektromagnetik'),
((SELECT id FROM kata WHERE kata='abang'), '1 kakak laki-laki; saudara tua laki-laki: --nya dua tahun lebih tua; 2 panggilan kpd orang laki-laki yg lebih tua atau tidak dikenal: tahukah -- jalan ke kelurahan?; 3 panggilan istri kpd suami: sudah dua hari -- dinas keluar kota; 4 panggilan kpd penjual sayur, penjual ikan, pengemudi becak, dsb: --, berapa harga ikan bawal ini per kilo?; 2 memanggil atau menyebut abang: ia ~ kpd saya'),
((SELECT id FROM kata WHERE kata='abang'), 'merah'),
((SELECT id FROM kata WHERE kata='abangan'), 'golongan masyarakat yg menganut agama Islam, tetapi tidak melaksanakan ajaran secara keseluruhan'),
((SELECT id FROM kata WHERE kata='abar'), '1 dinding; penghalang; penyekat; abar-abar; 2 rem; -- pintu Tek alat untuk menutup pintu secara perlahan-lahan untuk mengurangi (menghilangkan) bunyi (benturan); 2 menghambat; menahan; mengerem; tertahan: saya tadi ~ krn ada kecelakaan lalu lintas'),
((SELECT id FROM kata WHERE kata='abatisasi'), 'pemberantasan penyakit demam berdarah dng menaburkan bubuk abate'),
((SELECT id FROM kata WHERE kata='abatoar'), 'tempat pematongan hewan untuk umum yg diselenggarakan pemerintah'),
((SELECT id FROM kata WHERE kata='abau'), 'kura-kura rawa yg besar'),
